command:
ssh -i /home/jose/.ssh/n8n_bridge -o StrictHostKeyChecking=no jose@192.168.0.202 "cat > /tmp/verify_restart.sh << 'SHEOF'
#!/bin/bash
echo === TELEGRAM CONFIG ===
grep -A8 '^telegram:' /home/jose/.hermes/config.yaml | head -9
echo === RESTARTING GATEWAY ===
sudo systemctl restart hermes-gateway
sleep 8
sudo systemctl status hermes-gateway --no-pager | head -8
echo === LOGS ===
journalctl -u hermes-gateway -n 15 --no-pager 2>/dev/null | grep -v '^-- '
SHEOF
bash /tmp/verify_restart.sh"
